OKSkeletonTool={}function OKSkeletonTool.showSkeleton(a,b)if not a.showSyncSkeleton then return end;if System:iOS()then window:beginSyncSkeleton()for c,d in ipairs(b)do d:showSyncSkeleton()end else a:showSyncSkeleton()end end;function OKSkeletonTool.hideSkeleton(a,b)if not a.hideSyncSkeleton then return end;if System:iOS()then for c,d in ipairs(b)do d:hideSyncSkeleton()end else a:hideSyncSkeleton()end end
